require_once( 'view/QuickFormIncludes.php' );;
require_once( 'view/TabbedPages.php' );;

class portfolio_daily_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('portfolio_daily page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$idportfolio_daily = $fs->addElement('text', 'idportfolio_daily', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
;
		$username = $fs->addElement('text', 'username', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'The user' )
			->addFilter( 'trim' )
;
		$f_date = date("Y-m-d" );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'tradedate' => $f_date ) ) );
		$tradedate = $fs->addElement('text', 'tradedate', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'The date for this row of history' )
			->addFilter( 'trim' )
;
		$bookvalue = $fs->addElement('text', 'bookvalue', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'The book value of the portfolio on this date' )
;
		$marketvalue = $fs->addElement('text', 'marketvalue', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'The market value of the portfolio on this date' )
;
		$cash = $fs->addElement('text', 'cash', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Cash in the portfolio on this date' )
;
		$account = $fs->addElement('text', 'account', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'The account this record is for' )
			->addFilter( 'trim' )
;
	}
}
